    window.addEventListener('load', () => {
        AOS.init();
        setTimeout(() => {
            document.getElementById('loading-screen').style.opacity = '0';
            setTimeout(() => {
                document.getElementById('loading-screen').style.display = 'none';
                checkAuth();
                updateTime();
                setInterval(updateTime, 1e3);
                updateTipOfTheDay();
                translatePage();
                updateLangHeader();
            }, 500);
        }, 2e3);
    });

    function updateTime() {
        const e = new Date;
        document.getElementById('current-time').textContent = e.toLocaleTimeString('hi-IN', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    }

    function updateTipOfTheDay() {
        const e = new Date,
            t = Math.floor((e - new Date(e.getFullYear(), 0, 0)) / (1e3 * 60 * 60 * 24)) % farmingTips[currentLanguage].length;
        document.getElementById('tip-of-the-day').textContent = farmingTips[currentLanguage][t];
        document.getElementById('tip-number').textContent = `#${String(t + 1).padStart(2, '0')}`;
    }

    function checkAuth() {
        // Firebase will handle auth; just hide loading screen
        document.getElementById('loading-screen').style.opacity = '0';
        setTimeout(() => {
            document.getElementById('loading-screen').style.display = 'none';
        }, 500);
    }

    window.switchAuthTab = e => {
        document.querySelectorAll('.auth-tab,.auth-form').forEach(t => t.classList.remove('active'));
        e === 'login' ? (document.querySelectorAll('.auth-tab')[0].classList.add('active'), document.getElementById('login-form').classList.add('active')) :
            (document.querySelectorAll('.auth-tab')[1].classList.add('active'), document.getElementById('signup-form').classList.add('active'));
    };

    window.handleLogin = async (e) => {
        e.preventDefault();
        let email = document.getElementById('login-email').value;
        let password = document.getElementById('login-password').value;

        try {
            const userCredential = await auth.signInWithEmailAndPassword(email, password);
            const user = userCredential.user;

            if (!user.emailVerified) {
                await auth.signOut();
                document.getElementById('login-error').innerText = 'Please verify your email first. Check your inbox.';
                return;
            }

            // Email verified – create local session
            let userData = userDatabase[email] || { name: user.displayName || email.split('@')[0], email };
            userDatabase[email] = userData;
            localStorage.setItem('patukrishi_users', JSON.stringify(userDatabase));

            currentUser = userData;
            localStorage.setItem('patukrishi_session', JSON.stringify(currentUser));
            document.getElementById('auth-container').style.display = 'none';
            loadDashboard();
            showNotification('Login successful', 'success');
        } catch (error) {
            document.getElementById('login-error').innerText = error.message;
        }
    };

    window.handleSignup = async (e) => {
        e.preventDefault();
        let name = document.getElementById('signup-name').value;
        let email = document.getElementById('signup-email').value;
        let password = document.getElementById('signup-password').value;

        if (!name || !email || !password) {
            document.getElementById('signup-error').innerText = 'All fields required';
            return;
        }

        try {
            const userCredential = await auth.createUserWithEmailAndPassword(email, password);
            const user = userCredential.user;
            await user.updateProfile({ displayName: name });
            await user.sendEmailVerification();

            // Store user info locally (no password!)
            let userData = { name, email };
            userDatabase[email] = userData;
            localStorage.setItem('patukrishi_users', JSON.stringify(userDatabase));

            await auth.signOut(); // force verification before login
            showNotification('Verification email sent! Check your inbox (and spam).', 'success');
            switchAuthTab('login');
            document.getElementById('signup-form').reset();
        } catch (error) {
            document.getElementById('signup-error').innerText = error.message;
        }
    };

    window.logout = () => {
        auth.signOut();
        localStorage.removeItem('patukrishi_session');
        location.reload();
    };

